import type * as DMMF from '@prisma/dmmf'

/**
 * Maps a Prisma scalar type to its TypeScript equivalent in a REST API context.
 *
 * `DateTime` maps to `Date` since that is what the model represents; callers
 * are responsible for parsing ISO 8601 strings returned by the server.
 */
function scalarToTs(prismaType: string): string {
  switch (prismaType) {
    case 'String':
      return 'string'
    case 'Int':
    case 'Float':
    case 'Decimal':
      return 'number'
    case 'BigInt':
      return 'bigint'
    case 'Boolean':
      return 'boolean'
    case 'DateTime':
      return 'Date'
    case 'Json':
      return 'unknown'
    case 'Bytes':
      // Base64-encoded in JSON
      return 'string'
    default:
      return 'unknown'
  }
}

/** Returns the base TypeScript type name for a field (without list or null modifiers). */
function fieldBaseType(field: DMMF.Field): string {
  switch (field.kind) {
    case 'scalar':
      return scalarToTs(field.type)
    case 'enum':
    case 'object':
      return field.type
    default:
      return 'unknown'
  }
}

interface FieldAnnotation {
  /** Whether to use `?:` optional-property syntax rather than `| null` in the type. */
  optional: boolean
  tsType: string
}

/**
 * Returns the optional flag and full TypeScript type string for a model interface field.
 *
 * Relation fields use `?:` because they are not always present in REST responses.
 * Scalar/enum fields follow Prisma's `isRequired` flag: non-required fields get `| null`.
 */
function fieldAnnotation(field: DMMF.Field): FieldAnnotation {
  const base = fieldBaseType(field)
  const tsType = field.isList ? base + '[]' : base

  if (field.kind === 'object') {
    return { optional: true, tsType }
  }
  if (!field.isRequired) {
    return { optional: false, tsType: tsType + ' | null' }
  }
  return { optional: false, tsType }
}

/** Returns the fields that form the primary key of a model. */
function getIdFields(model: DMMF.Model): readonly DMMF.Field[] {
  const singles = model.fields.filter((f) => f.isId)
  if (singles.length > 0) return singles

  // Compound primary key defined via @@id([...])
  if (model.primaryKey) {
    return model.primaryKey.fields
      .map((name) => model.fields.find((f) => f.name === name))
      .filter((f): f is DMMF.Field => f !== undefined)
  }

  return []
}

/**
 * Returns fields suitable for CreateInput — excludes auto-generated,
 * read-only, and relation fields.
 */
function getCreateFields(model: DMMF.Model): readonly DMMF.Field[] {
  return model.fields.filter((f) => f.kind !== 'object' && !f.isReadOnly && !f.isGenerated)
}

/**
 * Returns a lowercase plural URL path segment for a model name
 * (e.g. `User` → `users`, `Category` → `categorys`).
 *
 * Intentionally simple — the REST server defines the actual resource paths.
 */
function toUrlSegment(modelName: string): string {
  const lower = modelName.charAt(0).toLowerCase() + modelName.slice(1)
  return lower.endsWith('s') ? lower : lower + 's'
}

/** Returns a camelCase property name for a model in the root client (e.g. `User` → `user`). */
function toPropName(modelName: string): string {
  return modelName.charAt(0).toLowerCase() + modelName.slice(1)
}

// ---------------------------------------------------------------------------
// Per-type generators
// ---------------------------------------------------------------------------

function generateEnum(e: DMMF.DatamodelEnum): string {
  const values = e.values.map((v) => "'" + v.name + "'").join(' | ')
  const doc = e.documentation ? '/** ' + e.documentation + ' */\n' : ''
  return doc + 'export type ' + e.name + ' = ' + values
}

function generateModelInterface(model: DMMF.Model): string {
  const fields = model.fields.map((field) => {
    const { optional, tsType } = fieldAnnotation(field)
    const doc = field.documentation ? '  /** ' + field.documentation + ' */\n  ' : '  '
    return doc + field.name + (optional ? '?' : '') + ': ' + tsType
  })
  const doc = model.documentation ? '/** ' + model.documentation + ' */\n' : ''
  return doc + 'export interface ' + model.name + ' {\n' + fields.join('\n') + '\n}'
}

function generateWhereUniqueInput(model: DMMF.Model): string {
  const ids = getIdFields(model)
  const fields =
    ids.length === 0
      ? ['  [key: string]: unknown']
      : ids.map((f) => '  ' + f.name + ': ' + fieldAnnotation(f).tsType)
  return 'export interface ' + model.name + 'WhereUniqueInput {\n' + fields.join('\n') + '\n}'
}

function generateCreateInput(model: DMMF.Model): string {
  const fields = getCreateFields(model).map((f) => {
    const base = fieldBaseType(f)
    const tsType = f.isList ? base + '[]' : base
    const fullType = f.isRequired ? tsType : tsType + ' | null'
    // Fields with defaults are optional when creating
    const optional = f.hasDefaultValue || !f.isRequired
    return '  ' + f.name + (optional ? '?' : '') + ': ' + fullType
  })
  return 'export interface ' + model.name + 'CreateInput {\n' + fields.join('\n') + '\n}'
}

function generateUpdateInput(model: DMMF.Model): string {
  const idFieldNames = new Set(getIdFields(model).map((f) => f.name))
  const fields = getCreateFields(model)
    .filter((f) => !idFieldNames.has(f.name))
    .map((f) => {
      const base = fieldBaseType(f)
      const tsType = f.isList ? base + '[]' : base
      // All fields are optional in update input
      return '  ' + f.name + '?: ' + tsType + ' | null'
    })
  return 'export interface ' + model.name + 'UpdateInput {\n' + fields.join('\n') + '\n}'
