  const n = model.name
  return [
    'export interface ' + n + 'FindManyParams {',
    '  skip?: number',
    '  take?: number',
    '  where?: Partial<' + n + '>',
    "  orderBy?: Partial<Record<keyof " + n + ", 'asc' | 'desc'>>",
    '}',
  ].join('\n')
