  if (ids.length === 0) return 'this.#baseUrl'
  if (ids.length === 1) {
    return "this.#baseUrl + '/' + String(params.where." + ids[0].name + ')'
  }
  const parts = ids.map((f) => "'" + f.name + "=' + String(params.where." + f.name + ')')
  return "this.#baseUrl + '?' + " + parts.join(" + '&' + ")
}

function generateModelClient(model: DMMF.Model): string {
  const n = model.name
  const segment = toUrlSegment(n)
  const urlExpr = uniqueUrlExpr(model)

  return [
    'export class ' + n + 'RestClient {',
    '  readonly #baseUrl: string',
    '  readonly #defaultOptions: RequestInit',
    '',
    '  constructor(baseUrl: string, defaultOptions: RequestInit = {}) {',
    "    this.#baseUrl = baseUrl + '/" + segment + "'",
    '    this.#defaultOptions = defaultOptions',
    '  }',
    '',
    '  /** Fetches a list of ' + n + ' records. */',
    '  async findMany(params: ' + n + 'FindManyParams = {}): Promise<' + n + '[]> {',
    '    const query = new URLSearchParams()',
    "    if (params.skip !== undefined) query.set('skip', String(params.skip))",
    "    if (params.take !== undefined) query.set('take', String(params.take))",
    '    const qs = query.toString()',
    "    const url = qs ? this.#baseUrl + '?' + qs : this.#baseUrl",
    "    const response = await fetch(url, { ...this.#defaultOptions, method: 'GET' })",
    '    if (!response.ok) throw new RestApiError(response, url)',
    '    return response.json() as Promise<' + n + '[]>',
    '  }',
    '',
    '  /** Fetches a single ' + n + ' record by its unique identifier, or `null` if not found. */',
    '  async findUnique(params: { where: ' + n + 'WhereUniqueInput }): Promise<' + n + ' | null> {',
    '    const url = ' + urlExpr,
    "    const response = await fetch(url, { ...this.#defaultOptions, method: 'GET' })",
    '    if (response.status === 404) return null',
    '    if (!response.ok) throw new RestApiError(response, url)',
    '    return response.json() as Promise<' + n + '>',
    '  }',
    '',
    '  /** Creates a new ' + n + ' record. */',
    '  async create(params: { data: ' + n + 'CreateInput }): Promise<' + n + '> {',
    '    const response = await fetch(this.#baseUrl, {',
    '      ...this.#defaultOptions,',
    "      method: 'POST',",
    "      headers: { ...this.#defaultOptions.headers, 'Content-Type': 'application/json' },",
    '      body: JSON.stringify(params.data),',
    '    })',
    '    if (!response.ok) throw new RestApiError(response, this.#baseUrl)',
    '    return response.json() as Promise<' + n + '>',
    '  }',
    '',
    '  /** Updates an existing ' + n + ' record by its unique identifier. */',
    '  async update(params: { where: ' + n + 'WhereUniqueInput; data: ' + n + 'UpdateInput }): Promise<' + n + '> {',
    '    const url = ' + urlExpr,
    '    const response = await fetch(url, {',
    '      ...this.#defaultOptions,',
    "      method: 'PATCH',",
    "      headers: { ...this.#defaultOptions.headers, 'Content-Type': 'application/json' },",
    '      body: JSON.stringify(params.data),',
    '    })',
    '    if (!response.ok) throw new RestApiError(response, url)',
    '    return response.json() as Promise<' + n + '>',
    '  }',
    '',
    '  /** Deletes a ' + n + ' record by its unique identifier. */',
    '  async delete(params: { where: ' + n + 'WhereUniqueInput }): Promise<' + n + '> {',
    '    const url = ' + urlExpr,
    "    const response = await fetch(url, { ...this.#defaultOptions, method: 'DELETE' })",
    '    if (!response.ok) throw new RestApiError(response, url)',
    '    return response.json() as Promise<' + n + '>',
    '  }',
    '}',
  ].join('\n')
}

function generateRootClient(models: readonly DMMF.Model[]): string {
  const propLines = models
    .map((m) => '  readonly ' + toPropName(m.name) + ': ' + m.name + 'RestClient')
    .join('\n')

  const ctorLines = models
    .map((m) => '    this.' + toPropName(m.name) + ' = new ' + m.name + 'RestClient(baseUrl, defaultOptions)')
    .join('\n')

  return [
    '/** Typed REST API client providing access to all Prisma model resources. */',
    'export class RestApiClient {',
    propLines,
    '',
    '  constructor(baseUrl: string, defaultOptions: RequestInit = {}) {',
    ctorLines,
    '  }',
    '}',
  ].join('\n')
}

// ---------------------------------------------------------------------------
// File-level assembly
// ---------------------------------------------------------------------------

const FILE_HEADER = [
  '/**',
  ' * This file was generated by @prisma/generator-rest-client.',
  ' * Do not edit it manually — re-run `prisma generate` to regenerate.',
  ' *',
  ' * DateTime fields are typed as `Date` but REST servers return ISO 8601 strings.',
  ' * Cast or parse them as needed after fetching.',
  ' */',
  '',
  '/* eslint-disable */',
  '',
  '/** Thrown when a REST API response has a non-OK HTTP status code. */',
  'export class RestApiError extends Error {',
  '  readonly status: number',
  '  readonly url: string',
  '',
  '  constructor(response: Response, url: string) {',
  "    super('REST API request to ' + url + ' failed with status ' + response.status + ' ' + response.statusText)",
  '    this.name = ' + "'RestApiError'",
  '    this.status = response.status',
  '    this.url = url',
  '  }',
  '}',
].join('\n')

/**
 * Generates the complete content of the `rest-client.ts` output file
 * from the DMMF datamodel.
 */
export function generateFileContent(datamodel: DMMF.Datamodel): string {
  const sections: string[] = [FILE_HEADER, '']

  if (datamodel.enums.length > 0) {
    sections.push('// Enums', '')
    for (const e of datamodel.enums) {
      sections.push(generateEnum(e), '')
    }
  }

  sections.push('// Model interfaces', '')
  for (const model of datamodel.models) {
    sections.push(generateModelInterface(model), '')
  }

  sections.push('// Input types', '')
  for (const model of datamodel.models) {
    sections.push(
      generateWhereUniqueInput(model),
      generateCreateInput(model),
      generateUpdateInput(model),
      generateFindManyParams(model),
      '',
    )
  }

  sections.push('// Model REST clients', '')
  for (const model of datamodel.models) {
    sections.push(generateModelClient(model), '')
  }

  sections.push('// Root client', '', generateRootClient(datamodel.models), '')

  return sections.join('\n')
}

