import fs from 'node:fs/promises'
import path from 'node:path'

import type { GeneratorOptions } from '@prisma/generator'

import { generateFileContent } from './template'

/**
 * Resolves the absolute output directory from the generator options.
 *
 * Prisma passes the `output` field as an `EnvValue` which may reference an
 * environment variable. If no output is configured, we fall back to a
 * `generated/rest-client` directory next to the schema file.
 */
function resolveOutputDir(options: GeneratorOptions): string {
  const { output } = options.generator
  const fallback = path.join(path.dirname(options.schemaPath), 'generated', 'rest-client')

  if (output === null) return fallback
  if (output.fromEnvVar !== null) {
    return process.env[output.fromEnvVar] ?? fallback
  }
  return output.value ?? fallback
}

/**
 * Generator `onGenerate` callback.
 *
 * Reads the DMMF datamodel from `options`, generates a typed REST API client,
 * and writes `rest-client.ts` into the configured output directory.
 */
export async function onGenerate(options: GeneratorOptions): Promise<void> {
  const outputDir = resolveOutputDir(options)

  await fs.mkdir(outputDir, { recursive: true })

  const content = generateFileContent(options.dmmf.datamodel)

  await fs.writeFile(path.join(outputDir, 'rest-client.ts'), content, 'utf-8')
}

