import { onGenerate } from './generator'

/**
 * The manifest and generate callbacks registered with the Prisma generator
 * protocol. Exported so they can be imported and tested independently.
 */
export const handler = {
  onManifest() {
    return {
      prettyName: 'REST API Client Generator',
      defaultOutput: './generated/rest-client',
    }
  },
  onGenerate,
}

/**
 * Registers the generator with the Prisma generator protocol by listening on
 * stdin for JSON-RPC messages from the Prisma CLI and writing responses to
 * stderr. This call is the side-effect that makes the module usable as a
 * generator process.
 */
generatorHandler(handler)

